#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long c1 = 0, c2 = 0, sumMod = 0;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            int r = x % 3;
            if (r == 1) c1++;
            else if (r == 2) c2++;
            sumMod = (sumMod + r) % 3;
        }
        if (sumMod != 0) {
            printf("-1\n");
        } else {
            long long pairs = c1 < c2 ? c1 : c2;
            long long diff = (c1 > c2) ? (c1 - c2) : (c2 - c1);
            long long extra = 2 * (diff / 3);
            printf("%lld\n", pairs + extra);
        }
    }
    return 0;
}

