#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        c1 = c2 = sum_mod = 0
        for _ in range(N):
            x = int(next(it))
            r = x % 3
            if r == 1:
                c1 += 1
            elif r == 2:
                c2 += 1
            sum_mod = (sum_mod + r) % 3
        if sum_mod != 0:
            out.append('-1')
        else:
            pairs = min(c1, c2)
            diff = abs(c1 - c2)
            extra = 2 * (diff // 3)
            out.append(str(pairs + extra))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

